package com.example.webviewapp

import android.Manifest
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.util.Log
import android.view.KeyEvent
import android.webkit.JsResult
import android.webkit.WebChromeClient
import android.webkit.WebView
import android.webkit.WebViewClient
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat

class MainActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private val TAG = "WebViewApp"
    // Use a remote URL for your web app, or a local asset HTML file
    private val webUrl = "file:///android_asset/index.html" // Example for a local asset

    // ActivityResultLauncher for camera permission
    private val requestCameraPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { isGranted: Boolean ->
            if (isGranted) {
                Log.d(TAG, "Camera permission granted by user.")
                // Inform JavaScript that permission was granted
                webView.post {
                    webView.evaluateJavascript("javascript:onCameraPermissionResult(true);", null)
                }
            } else {
                Log.d(TAG, "Camera permission denied by user.")
                // Inform JavaScript that permission was denied
                webView.post {
                    webView.evaluateJavascript("javascript:onCameraPermissionResult(false);", null)
                }
            }
        }

    // ActivityResultLauncher for notification permission (Android 13+)
    private val requestNotificationPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { isGranted: Boolean ->
            if (isGranted) {
                Log.d(TAG, "Notification permission granted by user.")
                // Inform JavaScript that permission was granted
                webView.post {
                    webView.evaluateJavascript("javascript:onNotificationPermissionResult(true);", null)
                }
            } else {
                Log.d(TAG, "Notification permission denied by user.")
                // Inform JavaScript that permission was denied
                webView.post {
                    webView.evaluateJavascript("javascript:onNotificationPermissionResult(false);", null)
                }
            }
        }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        webView = findViewById(R.id.webView)
        setupWebView()
        webView.loadUrl(webUrl)
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true // Essential for JavaScript to run
            domStorageEnabled = true // Enable HTML5 DOM storage (localStorage, sessionStorage)
            databaseEnabled = true // Enable HTML5 database storage
            allowFileAccess = true // Allow access to file URLs (important for local assets)
            // Other settings you might need:
            // mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW // For HTTPS pages loading HTTP resources
            // cacheMode = WebSettings.LOAD_DEFAULT // Cache handling
        }

        // Set a WebViewClient to handle page navigation within the WebView
        webView.webViewClient = object : WebViewClient() {
            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
                Log.d(TAG, "Page started loading: $url")
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                Log.d(TAG, "Page finished loading: $url")
            }

            override fun shouldOverrideUrlLoading(view: WebView?, url: String?): Boolean {
                url?.let {
                    // Example: Handle specific URL schemes or open external links
                    if (url.startsWith("http://") || url.startsWith("https://")) {
                        // Let WebView handle HTTP/HTTPS URLs (or you can open external browser for certain domains)
                        return false
                    } else if (url.startsWith("mailto:")) {
                        // Example: Open mail client for mailto links
                        startActivity(Intent(Intent.ACTION_SENDTO, Uri.parse(url)))
                        return true
                    }
                    // Add other custom scheme handling here if needed
                }
                return false // Let WebView handle default loading
            }
        }

        // Set a WebChromeClient to handle JavaScript dialogs (alert, confirm, prompt)
        // and console messages, as well as progress and title changes.
        webView.webChromeClient = object : WebChromeClient() {
            override fun onJsAlert(view: WebView?, url: String?, message: String?, result: JsResult?): Boolean {
                Log.d(TAG, "JS Alert: $message")
                // You can show a native AlertDialog here if you want
                result?.confirm() // Always confirm to prevent hanging
                return true
            }

            override fun onConsoleMessage(consoleMessage: android.webkit.ConsoleMessage?) {
                // Log JavaScript console messages to Android Logcat for debugging
                consoleMessage?.let {
                    Log.d(TAG, "WEB_CONSOLE: ${it.message()} -- From line ${it.lineNumber()} of ${it.sourceId()}")
                }
            }
        }

        // Add the JavaScript interface: "Android" will be the global JS object name
        webView.addJavascriptInterface(MyJavaScriptInterface(this), "Android")
    }

    // Handle back button presses for WebView navigation history
    override fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {
        if (keyCode == KeyEvent.KEYCODE_BACK && webView.canGoBack()) {
            webView.goBack()
            return true
        }
        return super.onKeyDown(keyCode, event)
    }

    // Methods to be called by MyJavaScriptInterface to trigger permission requests
    fun requestCameraPermission() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) != PackageManager.PERMISSION_GRANTED) {
            requestCameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        } else {
            // Permission already granted, immediately notify JS
            webView.post {
                webView.evaluateJavascript("javascript:onCameraPermissionResult(true);", null)
            }
        }
    }

    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) != PackageManager.PERMISSION_GRANTED) {
                requestNotificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
            } else {
                // Permission already granted, immediately notify JS
                webView.post {
                    webView.evaluateJavascript("javascript:onNotificationPermissionResult(true);", null)
                }
            }
        } else {
            // For Android versions below 13, POST_NOTIFICATIONS permission is not required at runtime
            webView.post {
                webView.evaluateJavascript("javascript:onNotificationPermissionResult(true);", null)
            }
        }
    }
}

MyJavaScriptInterface.kt
package com.example.webviewapp

import android.Manifest
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.os.Build
import android.webkit.JavascriptInterface
import android.widget.Toast
import androidx.core.app.ActivityCompat
import androidx.core.app.NotificationCompat
import androidx.core.app.NotificationManagerCompat
import androidx.core.content.ContextCompat

/**
 * This class provides a bridge for JavaScript in the WebView to call native Android functions.
 * Methods annotated with @JavascriptInterface can be called from JavaScript.
 */
class MyJavaScriptInterface(private val context: Context) {

    companion object {
        private const val PREFS_NAME = "WebViewAppPrefs"
        private const val NOTIFICATION_CHANNEL_ID = "WebViewAppChannel"
        private const val NOTIFICATION_ID = 1
    }

    // Using SharedPreferences for demonstrating simple native local storage
    private val sharedPreferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    /**
     * Shows a short Toast message on the Android device.
     * Callable from JavaScript as: Android.showToast("Your message");
     */
    @JavascriptInterface
    fun showToast(message: String) {
        Toast.makeText(context, message, Toast.LENGTH_SHORT).show()
    }

    /**
     * Requests camera access permission from the Android system.
     * If permission is already granted, it will notify the web app.
     * Otherwise, it will trigger the permission request via the MainActivity.
     * Callable from JavaScript as: Android.requestCameraAccess();
     */
    @JavascriptInterface
    fun requestCameraAccess() {
        if (ContextCompat.checkSelfPermission(context, Manifest.permission.CAMERA)
            == PackageManager.PERMISSION_GRANTED) {
            Toast.makeText(context, "Camera permission already granted!", Toast.LENGTH_SHORT).show()
            launchCameraApp()
        } else {
            Toast.makeText(context, "Requesting camera permission...", Toast.LENGTH_LONG).show()
            // Delegate permission request to the MainActivity context
            if (context is MainActivity) {
                context.requestCameraPermission()
            }
        }
    }

    /**
     * Launches the default camera application.
     * This is a demonstration of using a native feature after permission is granted.
     */
    private fun launchCameraApp() {
        val cameraIntent = Intent(android.provider.MediaStore.ACTION_IMAGE_CAPTURE)
        // Ensure there's an app that can handle the intent
        if (cameraIntent.resolveActivity(context.packageManager) != null) {
            context.startActivity(cameraIntent)
            Toast.makeText(context, "Launching camera app...", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(context, "No camera app found.", Toast.LENGTH_SHORT).show()
        }
    }

    /**
     * Saves a key-value pair to Android's SharedPreferences (native local storage).
     * Callable from JavaScript as: Android.saveToLocalStorage("key", "value");
     */
    @JavascriptInterface
    fun saveToLocalStorage(key: String, value: String) {
        with(sharedPreferences.edit()) {
            putString(key, value)
            apply()
        }
        Toast.makeText(context, "Saved '$key': '$value' to native storage.", Toast.LENGTH_SHORT).show()
    }

    /**
     * Reads a value from Android's SharedPreferences (native local storage) using a given key.
     * Returns null if the key is not found.
     * Callable from JavaScript as: var value = Android.readFromLocalStorage("key");
     */
    @JavascriptInterface
    fun readFromLocalStorage(key: String): String? {
        val value = sharedPreferences.getString(key, null)
        Toast.makeText(context, "Read '$key': '${value ?: "null"}' from native storage.", Toast.LENGTH_SHORT).show()
        return value
    }

    /**
     * Sends a native push notification.
     * Handles permission requests for Android 13 (API 33) and above.
     * Callable from JavaScript as: Android.sendPushNotification("Title", "Message");
     */
    @JavascriptInterface
    fun sendPushNotification(title: String, message: String) {
        // Request POST_NOTIFICATIONS permission for Android 13+
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU &&
            ContextCompat.checkSelfPermission(context, Manifest.permission.POST_NOTIFICATIONS) != PackageManager.PERMISSION_GRANTED) {
            Toast.makeText(context, "Requesting notification permission...", Toast.LENGTH_LONG).show()
            if (context is MainActivity) {
                context.requestNotificationPermission()
            }
            return // Exit, as permission is needed first
        }

        // Create notification channel for Android O (API 26) and above
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channelName = "WebView App Notifications"
            val channelDescription = "Notifications from the WebView hybrid app"
            val importance = android.app.NotificationManager.IMPORTANCE_DEFAULT
            val channel = android.app.NotificationChannel(NOTIFICATION_CHANNEL_ID, channelName, importance).apply {
                description = channelDescription
            }
            val notificationManager: android.app.NotificationManager =
                context.getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager
            notificationManager.createNotificationChannel(channel)
        }

        val builder = NotificationCompat.Builder(context, NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info) // Replace with your app's actual small icon
            .setContentTitle(title)
            .setContentText(message)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true) // Dismiss notification when clicked

        with(NotificationManagerCompat.from(context)) {
            // Check again for permission specifically for sending the notification
            // This covers cases where permission was granted synchronously for older Android versions
            // or if it was just granted via the Activity's requestPermission()
            if (ActivityCompat.checkSelfPermission(context, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED || Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU) {
                notify(NOTIFICATION_ID, builder.build())
                Toast.makeText(context, "Notification sent!", Toast.LENGTH_SHORT).show()
            } else {
                Toast.makeText(context, "Notification permission not granted, cannot send.", Toast.LENGTH_LONG).show()
            }
        }
    }
}

